import httpx, time

def call_with_rate_limit_awareness(client: httpx.Client, url: str) -> dict:
    response = client.get(url)
    # Proactively slow down when quota is running low
    remaining = response.headers.get("X-RateLimit-Remaining")
    reset_at = response.headers.get("X-RateLimit-Reset")
    if remaining and int(remaining) < 10 and reset_at:
        sleep_secs = max(0, float(reset_at) - time.time())
        time.sleep(sleep_secs + 0.5)
    if response.status_code == 429:
        retry_after = float(response.headers.get("Retry-After", 60))
        time.sleep(retry_after)
        return call_with_rate_limit_awareness(client, url)
    response.raise_for_status()
    return response.json()

import httpx
import re

def parse_link_header(header: str) -> dict[str, str]:
    '''Parse the Link header into a {rel: url} mapping.'''
    links = {}
    for part in header.split(','):
        match = re.match(r'<([^>]+)>.*rel="([^"]+)"', part.strip())
        if match:
            links[match.group(2)] = match.group(1)
    return links

def iter_github_issues(repo: str, token: str):
    with httpx.Client(headers={'Authorization': f'Bearer {token}'}) as client:
        url = f'https://api.github.com/repos/{repo}/issues'
        params = {'state': 'all', 'per_page': 100}
